const trigger = $('Webhook Trigger').first().json || {}
const headers = trigger.headers || {}
const secret = headers['x-pipeline-secret'] || headers['X-Pipeline-Secret']
const expected = $env.PIPELINE_SECRET

if (!secret || secret !== expected) {
  return [{ json: { authorized: false, error: 'unauthorized', status: 401 } }]
}

return [{ json: { authorized: true, startTime: Date.now() } }]

const companies = [
  { name: 'NVIDIA', assigneeId: 'nvidia-assignee-id',
    aliases: ['NVIDIA Corporation', 'NVIDIA Corp', 'Nvidia'] },
  { name: 'AMD', assigneeId: 'amd-assignee-id',
    aliases: ['Advanced Micro Devices', 'Advanced Micro Devices Inc', 'AMD'] },
  { name: 'Intel', assigneeId: 'intel-assignee-id',
    aliases: ['Intel Corporation', 'Intel Corp', 'Intel'] },
  { name: 'Google', assigneeId: 'google-assignee-id',
    aliases: ['Google LLC', 'Google Inc', 'Alphabet', 'DeepMind', 'Google DeepMind Technologies Limited'] },
  { name: 'Apple', assigneeId: 'apple-assignee-id',
    aliases: ['Apple Inc', 'Apple Computer', 'Apple'] }
]

const CPC_CODES = ['G06N', 'H01L']

const now = new Date()
const eightQuartersAgo = new Date(now)
eightQuartersAgo.setFullYear(eightQuartersAgo.getFullYear() - 2)
const dateFrom = eightQuartersAgo.toISOString().split('T')[0]
const dateTo = now.toISOString().split('T')[0]

const FIELDS = ['patent_id', 'patent_title', 'patent_abstract',
  'patent_date', 'assignee_organization', 'inventor_last_name',
  'inventor_first_name', 'cpc_section_id', 'cpc_subgroup_id']

async function patentsViewQuery(qFilter) {
  const body = {
    q: { _and: [
      { _or: CPC_CODES.map(code => ({ cpc_section_id: { _text_phrase: code } })) },
      qFilter,
      { patent_date: { _gte: dateFrom, _lte: dateTo } }
    ]},
    f: FIELDS,
    o: { per_page: 100, page: 1 }
  }
  try {
    const response = await $helpers.httpRequest({
      method: 'POST',
      url: 'https://api.patentsview.org/patents/query',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(body)
    })
    const data = typeof response === 'string' ? JSON.parse(response) : response
    return data.patents || []
  } catch (e) {
    return { __error: e.message }
  }
}

const rawResults = []
const errors = []

for (const company of companies) {
  const seen = new Set()
  let combined = []

  const byId = await patentsViewQuery({ assignee_id: { _text_phrase: company.assigneeId } })
  if (Array.isArray(byId)) {
    for (const p of byId) { if (p.patent_id && !seen.has(p.patent_id)) { seen.add(p.patent_id); combined.push(p) } }
  } else if (byId && byId.__error) {
    errors.push({ company: company.name, source: 'assignee_id', error: byId.__error })
  }

  if (combined.length === 0) {
    for (const alias of company.aliases) {
      const byAlias = await patentsViewQuery({ assignee_organization: { _text_phrase: alias } })
      if (Array.isArray(byAlias)) {
        for (const p of byAlias) { if (p.patent_id && !seen.has(p.patent_id)) { seen.add(p.patent_id); combined.push(p) } }
      } else if (byAlias && byAlias.__error) {
        errors.push({ company: company.name, source: 'alias:' + alias, error: byAlias.__error })
      }
    }
  }

  if (combined.length > 0) {
    rawResults.push({ company: company.name, patents: combined, fetchedAt: new Date().toISOString() })
  } else {
    rawResults.push({ company: company.name, patents: [], fetchedAt: new Date().toISOString() })
  }
}

return [{ json: { rawResults, fetchErrors: errors, fetchedAt: new Date().toISOString() } }]

const items = $input.all()

let previousRow = null
let rawResults = []
let fetchedAt = new Date().toISOString()
let fetchErrors = []

for (const it of items) {
  const j = it.json || {}
  if (Array.isArray(j) && j.length > 0 && (j[0].leaderboard !== undefined || j[0].quarterly_stats !== undefined)) {
    previousRow = j[0]
  } else if (j.leaderboard !== undefined || j.quarterly_stats !== undefined) {
    previousRow = j
  } else if (Array.isArray(j.rawResults)) {
    rawResults = j.rawResults
    fetchedAt = j.fetchedAt || fetchedAt
    fetchErrors = j.fetchErrors || []
  }
}

function parseMaybe(v) {
  if (v == null) return null
  if (typeof v === 'object') return v
  try { const p = JSON.parse(v); return typeof p === 'string' ? JSON.parse(p) : p } catch (e) { return null }
}

const prevLeaderboard = previousRow ? (parseMaybe(previousRow.leaderboard) || []) : []
const previousConcepts = {}
const previousInventors = {}
for (const c of prevLeaderboard) {
  if (c && c.company) {
    previousConcepts[c.company] = [...(c.newConcepts || []), ...(c.emergingThemes || [])]
    previousInventors[c.company] = c.knownInventors || []
  }
}

const seen = new Set()
const cleaned = []
for (const result of rawResults) {
  for (const patent of (result.patents || [])) {
    const id = patent.patent_id
    if (!id || seen.has(id)) continue
    seen.add(id)

    const title = (patent.patent_title || '').trim()
    if (!title) continue

    const dateRaw = patent.patent_date
    const date = dateRaw ? new Date(dateRaw) : null
    if (!date || isNaN(date.getTime())) continue

    const year = date.getUTCFullYear()
    const quarter = Math.floor(date.getUTCMonth() / 3) + 1
    const quarterLabel = `${year}-Q${quarter}`

    let inventors = []
    if (Array.isArray(patent.inventors) && patent.inventors.length) {
      inventors = patent.inventors.map(inv =>
        `${(inv.inventor_first_name || '').trim()} ${(inv.inventor_last_name || '').trim()}`.trim()
      ).filter(Boolean)
    } else if (Array.isArray(patent.inventor_last_name)) {
      const firsts = Array.isArray(patent.inventor_first_name) ? patent.inventor_first_name : []
      inventors = patent.inventor_last_name.map((ln, idx) => {
        const f = (firsts[idx] && (firsts[idx].inventor_first_name || firsts[idx])) || ''
        const l = (ln && (ln.inventor_last_name || ln)) || ''
        return `${String(f).trim()} ${String(l).trim()}`.trim()
      }).filter(Boolean)
    }

    let cpcCodes = []
    if (Array.isArray(patent.cpcs)) cpcCodes = patent.cpcs.map(c => c.cpc_subgroup_id || c.cpc_section_id).filter(Boolean)
    else if (Array.isArray(patent.cpc_subgroup_id)) cpcCodes = patent.cpc_subgroup_id.map(c => c.cpc_subgroup_id || c).filter(Boolean)
    else if (patent.cpc_section_id) cpcCodes = [patent.cpc_section_id]

    cleaned.push({
      patentId: id,
      company: result.company,
      title,
      abstract: (patent.patent_abstract || '').slice(0, 500),
      filingDate: dateRaw,
      quarterLabel, year, quarter,
      inventors,
      inventorCount: inventors.length,
      cpcCodes,
      assignee: patent.assignee_organization || result.company
    })
  }
}

return [{ json: {
  patents: cleaned, totalCount: cleaned.length, fetchedAt,
  previousConcepts, previousInventors, fetchErrors
} }]

const { patents, previousConcepts, previousInventors, fetchErrors } = $input.first().json

const CPC_CATEGORIES = {
  'G06N': 'AI/ML Algorithms',
  'G06N3': 'Neural Networks',
  'G06N3/063': 'AI Hardware',
  'G06N20': 'Machine Learning',
  'H01L': 'Semiconductor Devices',
  'H01L29': 'Transistors',
  'H01L21': 'Semiconductor Manufacturing'
}

function maxCpcDepth(codes) {
  let maxDepth = 0
  for (const c of codes || []) {
    const depth = String(c).split(/[\/]/).join('').length / 4
    if (depth > maxDepth) maxDepth = depth
  }
  return Math.min(maxDepth, 4)
}

const categorized = patents.map(p => {
  const primaryCategory = (p.cpcCodes || []).reduce((best, code) => {
    const match = Object.keys(CPC_CATEGORIES)
      .sort((a, b) => b.length - a.length)
      .find(k => String(code).startsWith(k))
    return match ? CPC_CATEGORIES[match] : best
  }, 'General Technology')

  const abstractScore = Math.min((p.abstract || '').length / 500, 1) * 0.4
  const inventorScore = Math.min((p.inventorCount || 0) / 5, 1) * 0.3
  const cpcScore = (maxCpcDepth(p.cpcCodes) / 4) * 0.3
  const qualityWeight = Math.round((abstractScore + inventorScore + cpcScore) * 1000) / 1000

  return { ...p, primaryCategory, qualityWeight }
})

const quarterlyMap = {}
for (const patent of categorized) {
  const key = `${patent.company}::${patent.quarterLabel}`
  if (!quarterlyMap[key]) {
    quarterlyMap[key] = {
      company: patent.company, quarter: patent.quarterLabel,
      year: patent.year, quarterNum: patent.quarter,
      count: 0, weighted: 0, patents: [], inventors: new Set()
    }
  }
  quarterlyMap[key].count++
  quarterlyMap[key].weighted += patent.qualityWeight
  quarterlyMap[key].patents.push({ title: patent.title, abstract: patent.abstract })
  patent.inventors.forEach(inv => quarterlyMap[key].inventors.add(inv))
}

const companies = ['NVIDIA', 'AMD', 'Intel', 'Google', 'Apple']
const quarterlyStats = []

for (const company of companies) {
  const companyQuarters = Object.values(quarterlyMap)
    .filter(q => q.company === company)
    .sort((a, b) => a.year !== b.year ? a.year - b.year : a.quarterNum - b.quarterNum)

  for (let i = 0; i < companyQuarters.length; i++) {
    const current = companyQuarters[i]
    const prior = companyQuarters[i - 1]
    const priorYear = companyQuarters.find(q => q.year === current.year - 1 && q.quarterNum === current.quarterNum)

    const qoqChange = prior ? ((current.count - prior.count) / Math.max(prior.count, 1)) * 100 : 0
    const yoyChange = priorYear ? ((current.count - priorYear.count) / Math.max(priorYear.count, 1)) * 100 : 0
    const velocityScore = Math.min(100, Math.max(0, Math.round(50 + qoqChange * 0.5)))
    const zone = qoqChange > 50 ? 'ACCELERATING' : qoqChange < -20 ? 'DECELERATING' : 'STEADY'

    quarterlyStats.push({
      company, quarter: current.quarter, year: current.year, quarterNum: current.quarterNum,
      filingCount: current.count,
      weightedFilingCount: Math.round(current.weighted * 100) / 100,
      qoqChange: Math.round(qoqChange), yoyChange: Math.round(yoyChange),
      velocityScore, zone, uniqueInventors: current.inventors.size,
      patents: current.patents
    })
  }
}

const latestPerCompany = companies.map(c => {
  const qs = quarterlyStats.filter(q => q.company === c)
  return qs[qs.length - 1] || { company: c, filingCount: 0, weightedFilingCount: 0, qoqChange: 0, yoyChange: 0, velocityScore: 0, zone: 'STEADY' }
})

return [{ json: {
  quarterlyStats, latestPerCompany,
  allPatents: categorized,
  previousConcepts, previousInventors,
  fetchErrors,
  timestamp: new Date().toISOString(),
  date: new Date().toISOString().split('T')[0]
}}]

const data = $input.first().json
const { allPatents, sufficientCompanies, previousConcepts, previousInventors } = data
const sufficientNames = new Set(sufficientCompanies.map(c => c.company))

const abstractsByCompany = {}
const inventorsByCompany = {}
for (const company of sufficientNames) {
  const list = allPatents.filter(p => p.company === company)
  abstractsByCompany[company] = list.slice(-20).map(p => ({
    title: p.title, abstract: p.abstract, quarter: p.quarterLabel, qualityWeight: p.qualityWeight
  }))
  inventorsByCompany[company] = [...new Set(list.flatMap(p => p.inventors || []))]
}

return [{ json: {
  ...data,
  latestPerCompany: sufficientCompanies,
  abstractsByCompany,
  inventorsByCompany,
  previousConcepts: previousConcepts || {},
  previousInventors: previousInventors || {}
}}]

parameters.text:
=Analyse cross-company patent patterns to detect convergence and divergence.

Return ONLY valid JSON object (NOT an array):
{
  "convergenceTopics": string[],
  "divergenceTopics": [{ "topic": string, "company": string }],
  "leaderByCategory": [{ "category": string, "leader": string }],
  "strategicInsight": string,
  "confidenceLevel": number
}

Patent data: {{ JSON.stringify($json.abstractsByCompany) }}

parameters.jsCode:
function parseLlm(text) {
  if (text == null) return null
  if (typeof text === 'object') return text
  try {
    const clean = (text + '').replace(/^```[\w]*\n?/m, '').replace(/\n?```$/m, '').trim()
    return JSON.parse(clean)
  } catch (e) { return { __parseError: e.message } }
}

const pipelineData = $('Aggregate for Claude').first().json
const startTimeRaw = (() => { try { return $('Security Gate').first().json.startTime } catch (e) { return null } })()
const startTime = typeof startTimeRaw === 'number' ? startTimeRaw : Date.now() - 1

const items = $input.all()
let velocityScores = null, conceptNovelty = null, inventorNetwork = null
let convergence = null, strategicIntent = null, breakthroughData = null
const pendingErrors = []

for (let idx = 0; idx < items.length; idx++) {
  const parsed = parseLlm(items[idx].json && items[idx].json.text)
  if (!parsed || parsed.__parseError) {
    pendingErrors.push({ source: `claude_output_${idx}`, type: 'PARSE_FAILURE', detail: parsed && parsed.__parseError ? parsed.__parseError : 'null output' })
    continue
  }

  if (Array.isArray(parsed) && parsed.length > 0) {
    const first = parsed[0]
    if ('velocityScore' in first && 'trend' in first) velocityScores = parsed
    else if ('breakthroughScore' in first) breakthroughData = parsed
    else if ('noveltyScore' in first) conceptNovelty = parsed
    else if ('teamExpansionSignal' in first) inventorNetwork = parsed
    else if ('intent' in first && 'keyTechnicalThemes' in first) strategicIntent = parsed
    else pendingErrors.push({ source: `claude_output_${idx}`, type: 'UNRECOGNISED_SHAPE', detail: Object.keys(first) })
  } else if (parsed && typeof parsed === 'object' && !Array.isArray(parsed)) {
    if ('convergenceTopics' in parsed) convergence = parsed
    else pendingErrors.push({ source: `claude_output_${idx}`, type: 'UNRECOGNISED_SHAPE', detail: Object.keys(parsed) })
  }
}

velocityScores  = velocityScores  || []
conceptNovelty  = conceptNovelty  || []
inventorNetwork = inventorNetwork || []
convergence     = convergence     || {}
strategicIntent = strategicIntent || []
breakthroughData = breakthroughData || []

const byCompany = {}
for (const v of velocityScores) {
  if (!v || !v.company) continue
  byCompany[v.company] = { company: v.company, velocityScore: v.velocityScore, trend: v.trend, velocityInsight: v.insight, velocityConfidence: v.confidenceLevel }
}
for (const c of conceptNovelty) {
  if (!c || !c.company) continue
  byCompany[c.company] = byCompany[c.company] || { company: c.company }
  Object.assign(byCompany[c.company], { newConcepts: c.newConcepts || [], emergingThemes: c.emergingThemes || [], noveltyScore: c.noveltyScore, noveltyConfidence: c.confidenceLevel })
}
for (const i of inventorNetwork) {
  if (!i || !i.company) continue
  byCompany[i.company] = byCompany[i.company] || { company: i.company }
  Object.assign(byCompany[i.company], { newInventorCount: i.newInventorCount, teamExpansionSignal: i.teamExpansionSignal, inventorInsight: i.insight, inventorConfidence: i.confidenceLevel })
}
for (const s of strategicIntent) {
  if (!s || !s.company) continue
  byCompany[s.company] = byCompany[s.company] || { company: s.company }
  Object.assign(byCompany[s.company], { strategicIntent: s.intent, intentConfidence: s.confidence, intentReasoning: s.reasoning, keyTechnicalThemes: s.keyTechnicalThemes || [] })
}
for (const b of breakthroughData) {
  if (!b || !b.company) continue
  byCompany[b.company] = byCompany[b.company] || { company: b.company }
  Object.assign(byCompany[b.company], { breakthroughPatents: b.breakthroughPatents || [], breakthroughScore: b.breakthroughScore, breakthroughConfidence: b.confidenceLevel })
}

const latestMap = {}
for (const c of (pipelineData.latestPerCompany || [])) latestMap[c.company] = c
for (const company of Object.keys(byCompany)) {
  const q = latestMap[company] || {}
  byCompany[company].filingCount = q.filingCount || 0
  byCompany[company].qoqChange = q.qoqChange || 0
  byCompany[company].yoyChange = q.yoyChange || 0
  byCompany[company].knownInventors = (pipelineData.inventorsByCompany && pipelineData.inventorsByCompany[company]) || []
}

function investmentSignalFor(c) {
  const core = [c.velocityScore, c.trend, c.teamExpansionSignal]
  if (core.some(v => v == null || v === 'INSUFFICIENT_DATA')) return 'INSUFFICIENT_DATA'
  if (c.velocityScore > 70 && c.trend === 'ACCELERATING' && c.teamExpansionSignal === 'EXPANDING') return 'ACCUMULATE'
  if ((c.breakthroughScore || 0) > 60) return 'WATCH'
  if (c.trend === 'STEADY') return 'HOLD'
  if (c.trend === 'DECELERATING') return 'REDUCE'
  return 'HOLD'
}

const signalExpiresAt = new Date(Date.now() + 90 * 24 * 60 * 60 * 1000).toISOString()
for (const company of Object.keys(byCompany)) {
  byCompany[company].investmentSignal = investmentSignalFor(byCompany[company])
  byCompany[company].signalExpiresAt = signalExpiresAt
}

const insufficient = (pipelineData.insufficientCompanies || []).map(c => ({
  ...c,
  investmentSignal: 'INSUFFICIENT_DATA',
  signalExpiresAt
}))

const leaderboard = [
  ...Object.values(byCompany),
  ...insufficient
].sort((a, b) => {
  const av = a.velocityScore == null ? -Infinity : a.velocityScore
  const bv = b.velocityScore == null ? -Infinity : b.velocityScore
  return bv - av
})

const agentMetadata = {
  agentName: 'PatentVelocityAgent',
  agentVersion: '1.0',
  promptVersion: 'v1.0',
  modelUsed: 'claude-sonnet-4-6',
  runDurationMs: Date.now() - startTime,
  pendingErrors,
  fetchErrors: pipelineData.fetchErrors || []
}

return [{ json: {
  leaderboard,
  convergence,
  quarterlyStats: pipelineData.quarterlyStats || [],
  timestamp: pipelineData.timestamp,
  date: pipelineData.date,
  totalPatentsAnalyzed: (pipelineData.allPatents || []).length,
  agentMetadata,
  insufficientCompanies: pipelineData.insufficientCompanies || []
}}]

// Inspect insert response. If non-2xx, write a row to error_log.
// Also writes any pendingErrors from agentMetadata as separate error_log rows.
const http = $input.first().json || {}
const body = http.body || http
const statusCode = http.statusCode || http.status || 0
const sigItems = $('Signal Aggregator').first().json || {}
const agentMeta = sigItems.agentMetadata || {}

const inserted = Array.isArray(body) ? body[0] : (body && body.id ? body : null)
const runId = inserted ? inserted.id : null

const rows = []
if (statusCode < 200 || statusCode >= 300) {
  rows.push({
    run_id: runId,
    node_name: 'Insert to Supabase',
    error_type: 'INSERT_FAILED',
    error_detail: { status: statusCode, body }
  })
}
for (const e of (agentMeta.pendingErrors || [])) {
  rows.push({ run_id: runId, node_name: 'Signal Aggregator', error_type: e.type || 'CLAUDE_OUTPUT_ERROR', error_detail: e })
}
for (const e of (agentMeta.fetchErrors || [])) {
  rows.push({ run_id: runId, node_name: 'Fetch Patent Data', error_type: 'FETCH_FAILED', error_detail: e })
}

return [{ json: {
  runId,
  insertStatus: statusCode,
  insertOk: statusCode >= 200 && statusCode < 300,
  errorRows: rows,
  // forward original aggregated data so downstream nodes still have it
  ...sigItems
}}]

parameters.jsonBody:
={{ JSON.stringify({
  agentName: 'PatentVelocityAgent',
  agentVersion: '1.0',
  runId: $('Parse Insert + Build Errors').first().json.runId,
  timestamp: $('Signal Aggregator').first().json.timestamp,
  signals: ($('Signal Aggregator').first().json.leaderboard || []).map(c => ({
    company: c.company,
    signalType: 'PATENT_VELOCITY',
    direction: c.trend,
    strength: c.velocityScore,
    confidence: c.intentConfidence,
    investmentSignal: c.investmentSignal,
    breakthroughScore: c.breakthroughScore,
    expiresAt: c.signalExpiresAt
  }))
}) }}
